import sys

def main():
    import sys
    input = sys.stdin.read
    data = input().split()
    N = int(data[0])
    A = data[1]

    length = 3 ** N
    target = '0' if A.count('1') < length // 2 else '1'

    def get_majority(s):
        count = {'0': 0, '1': 0}
        for c in s:
            count[c] += 1
        return '0' if count['0'] > count['1'] else '1'

    def apply_operation(s):
        res = []
        for i in range(0, len(s), 3):
            group = s[i:i+3]
            res.append(get_majority(group))
        return ''.join(res)

    current = A
    for _ in range(N):
        current = apply_operation(current)

    min_changes = float('inf')
    for i in range(length):
        if A[i] == target:
            continue
        temp = A[:i] + ('1' if A[i] == '0' else '0') + A[i+1:]
        temp_str = temp
        for _ in range(N):
            temp_str = apply_operation(temp_str)
        if temp_str[0] != target:
            min_changes = min(min_changes, 1)

    print(min_changes)

if __name__ == "__main__":
    main()
